VALUES
  ('optometrist-moex-02544', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關兒童低視力輔具的敘述，下列何者正確？', '["兒童使用手持式放大鏡時常遇到困難，故需使用最高倍率", "低視力兒童因有眩光欲配戴濾光眼鏡時，若希望色彩較不失真之考量下，配戴淺黃色之濾光眼鏡較灰 色濾光眼鏡為佳", "兒童閱讀時有跳行跳字的問題時，可使用閱讀規此類非光學輔具協助閱讀", "兒童在進行電影欣賞、觀賞球賽時可使用高度正眼鏡輔具方便觀賞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02545', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '針對低視力兒童檢查視力的辦法，下列敘述何者正確？', '["對於無法接受視力檢查之嬰幼兒，使用視網膜電位圖檢測，其檢查結果為正常，可預測患童不會有低視力", "為了吸引兒童注意力，可使用符號或圖案式的視力表", "視動性眼震檢查可用來檢測有無先天性眼球震顫", "亂點圖可用來做單眼立體感的視力篩檢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02546', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '小華是8歲的低視力小學生，他所能獲得的輔具資源有？①各縣市特教中心  ②各縣市輔具資源中心', '["高中職及大專校院輔具中心", "職務再設計中心  ⑤各縣市生活重建中心", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02547', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '針對視障者手杖的敘述，下列何者正確？', '["手杖長度以到患者胸口為主，長度可略減3-5 cm以方便收納", "手杖使用以杖身全白設計為主，國際通用不可改變", "手杖具有探索、保護及身分識別等作用", "如果有導盲犬的帶領，為避免影響導盲犬的行徑，手杖則可暫時不用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02548', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '目前臺灣低視力照護的服務敘述，何者正確？', '["提供低視力照護服務的專業人員只以醫事人員為主", "政府提供的低視力照護服務只以各縣市的輔具中心為主", "專業的醫事人員是低視力照護的起點，在初步處理後即不屬醫事人員的服務範疇", "低視力照護服務在各種專業的合作下，依個案的主訴需求為主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02549', 'optometrist', 'optometrist-moex-107-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列對視力的敘述何者正確？', '["視力值與對比敏感度絕對無相關", "視力值的量測比功能性視覺觀察來得重要許多", "對於認知功能或注意力不足的病患無法量測視力值，只能以電位檢查代替", "近視力的量測可輔以文章式的視力表進行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "d772395b4cf1", "answer_pdf_sha1": "9d3d9d30f444", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
